dtsPropsFor.GScottLogo:
/** Rendered height in px (default 32). */
  height?: number;
  /** Increment to replay the typewriter animation. */
  animKey?: number;

dtsPropsFor.IndexPill:
/** Short label, e.g. "S&P", "RUT", "VIX". */
  label: string;
  /** Current index value. */
  value: number;
  /** Day percent change, e.g. -0.42. */
  changePct: number;
  /** When true, sentiment inverts and label/value render in amber (VIX style). */
  isVix?: boolean;
